<?php
require_once __DIR__ . '/../helpers/rooms.php';$me=current_user();$id=(int)($_GET['room_id']??0);$room=room_by_id($id);if(!$room)json_response(['success'=>false,'message'=>'Room not found'],404);
$seats=db()->prepare("SELECT s.*,u.name,u.username,COALESCE(u.profile_photo,p.profile_photo) profile_photo,rp.raised_hand FROM room_seats s LEFT JOIN users u ON u.id=s.user_id LEFT JOIN user_profiles p ON p.user_id=u.id LEFT JOIN room_participants rp ON rp.room_id=s.room_id AND rp.user_id=s.user_id WHERE s.room_id=? ORDER BY s.seat_number");$seats->execute([$id]);
$people=db()->prepare("SELECT rp.*,u.name,u.username,COALESCE(u.profile_photo,p.profile_photo) profile_photo FROM room_participants rp JOIN users u ON u.id=rp.user_id LEFT JOIN user_profiles p ON p.user_id=u.id WHERE rp.room_id=? AND rp.left_at IS NULL ORDER BY FIELD(rp.role,'owner','coadmin','speaker','listener'),rp.joined_at");$people->execute([$id]);
$messages=db()->prepare("SELECT m.*,u.name,u.username,COALESCE(u.profile_photo,p.profile_photo) profile_photo FROM room_messages m LEFT JOIN users u ON u.id=m.user_id LEFT JOIN user_profiles p ON p.user_id=u.id WHERE m.room_id=? ORDER BY m.id DESC LIMIT 80");$messages->execute([$id]);
$queue=db()->prepare("SELECT q.*,u.name requested_by_name FROM room_video_queue q JOIN users u ON u.id=q.requested_by WHERE q.room_id=? AND q.status NOT IN('removed') ORDER BY FIELD(q.status,'playing','approved','pending','played','rejected'),q.id");$queue->execute([$id]);
json_response(['success'=>true,'room'=>$room,'my_role'=>room_role($id,(int)$me['id']),'seats'=>$seats->fetchAll(),'participants'=>$people->fetchAll(),'messages'=>array_reverse($messages->fetchAll()),'video_queue'=>$queue->fetchAll()]);
